import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import AdminLayout from '../components/admin/AdminLayout';
import authService from '../services/authService';
import api from '../services/api';
import { contentService } from '../services/cmsService';

export default function AdminDashboard() {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('content');
  const [cmsStatus, setCmsStatus] = useState('loading');
  const [userPages, setUserPages] = useState([]);
  const [selectedPage, setSelectedPage] = useState(null);
  const [pageSections, setPageSections] = useState([]);
  const [showNewPageModal, setShowNewPageModal] = useState(false);
  const [showSectionModal, setShowSectionModal] = useState(false);
  const [showCardModal, setShowCardModal] = useState(false);
  const [newPageForm, setNewPageForm] = useState({ slug: '', title: '', isPublished: false });
  const [sectionForm, setSectionForm] = useState({ type: 'default', title: '', content: '', position: 0 });
  const [cardForm, setCardForm] = useState({ title: '', description: '', icon: '' });
  const [editingCardSectionId, setEditingCardSectionId] = useState(null);

  const [services, setServices] = useState([]);
  const [faqs, setFaqs] = useState([]);
  const [offers, setOffers] = useState([]);
  const [showServiceModal, setShowServiceModal] = useState(false);
  const [showFaqModal, setShowFaqModal] = useState(false);
  const [showOfferModal, setShowOfferModal] = useState(false);
  const [editingService, setEditingService] = useState(null);
  const [editingFaq, setEditingFaq] = useState(null);
  const [editingOffer, setEditingOffer] = useState(null);
  const [serviceForm, setServiceForm] = useState({ title: '', description: '', icon: '', position: 0 });
  const [faqForm, setFaqForm] = useState({ question: '', answer: '', position: 0 });
  const [offerForm, setOfferForm] = useState({ name: '', description: '', price: '', badge: '', features: [], isPopular: false, position: 0 });

  const [contentData, setContentData] = useState({
    hero: null, benefits: null, features: null, pricing: null, steps: null, faq: null, cta: null
  });
  const [showEditModal, setShowEditModal] = useState(false);
  const [editingStaticSection, setEditingStaticSection] = useState(null);
  const [formData, setFormData] = useState({});

  useEffect(() => {
    if (!authService.isAdmin()) {
      navigate('/login');
      return;
    }
    checkCmsStatus();
    loadHybridContent();
  }, []);

  const checkCmsStatus = async () => {
    try {
      await api.get('/admin/test');
      setCmsStatus('available');
      loadUserPages();
    } catch (e) {
      setCmsStatus('unavailable');
    }
    loadContentData();
  };

  const loadHybridContent = async () => {
    try {
      const [srvs, fqs, offs] = await Promise.all([
        contentService.getAdminServices(),
        contentService.getAdminFaqs(),
        contentService.getAdminOffers()
      ]);
      setServices(srvs || []);
      setFaqs(fqs || []);
      setOffers(offs || []);
    } catch (e) {
      console.log('Hybrid content not available yet');
    }
  };

  const handleCreateService = async (e) => {
    e.preventDefault();
    try {
      if (editingService) {
        await contentService.updateService(editingService.id, serviceForm);
      } else {
        await contentService.createService(serviceForm);
      }
      setShowServiceModal(false);
      setServiceForm({ title: '', description: '', icon: '', position: 0 });
      setEditingService(null);
      loadHybridContent();
    } catch (err) {
      alert('Erreur: ' + err.message);
    }
  };

  const handleDeleteService = async (id) => {
    if (!window.confirm('Supprimer ce service ?')) return;
    try {
      await contentService.deleteService(id);
      loadHybridContent();
    } catch (err) {
      alert('Erreur: ' + err.message);
    }
  };

  const handleCreateFaq = async (e) => {
    e.preventDefault();
    try {
      if (editingFaq) {
        await contentService.updateFaq(editingFaq.id, faqForm);
      } else {
        await contentService.createFaq(faqForm);
      }
      setShowFaqModal(false);
      setFaqForm({ question: '', answer: '', position: 0 });
      setEditingFaq(null);
      loadHybridContent();
    } catch (err) {
      alert('Erreur: ' + err.message);
    }
  };

  const handleDeleteFaq = async (id) => {
    if (!window.confirm('Supprimer cette FAQ ?')) return;
    try {
      await contentService.deleteFaq(id);
      loadHybridContent();
    } catch (err) {
      alert('Erreur: ' + err.message);
    }
  };

  const handleCreateOffer = async (e) => {
    e.preventDefault();
    try {
      if (editingOffer) {
        await contentService.updateOffer(editingOffer.id, offerForm);
      } else {
        await contentService.createOffer(offerForm);
      }
      setShowOfferModal(false);
      setOfferForm({ name: '', description: '', price: '', badge: '', features: [], isPopular: false, position: 0 });
      setEditingOffer(null);
      loadHybridContent();
    } catch (err) {
      alert('Erreur: ' + err.message);
    }
  };

  const handleDeleteOffer = async (id) => {
    if (!window.confirm('Supprimer cette offre ?')) return;
    try {
      await contentService.deleteOffer(id);
      loadHybridContent();
    } catch (err) {
      alert('Erreur: ' + err.message);
    }
  };

  const loadUserPages = async () => {
    try {
      const response = await api.get('/admin/pages');
      setUserPages(response.data || []);
    } catch (e) { setUserPages([]); }
  };

  const loadPageSections = async (pageId) => {
    try {
      const response = await api.get(`/admin/pages/${pageId}`);
      setPageSections(response.data?.sections || []);
    } catch (e) { 
      console.log('CMS tables not available yet');
      setPageSections([]); 
    }
  };

  const handleSelectPage = (page) => { setSelectedPage(page); loadPageSections(page.id); };

  const handleCreatePage = async (e) => {
    e.preventDefault();
    try {
      await api.post('/admin/pages', newPageForm);
      setShowNewPageModal(false);
      setNewPageForm({ slug: '', title: '', isPublished: false });
      loadUserPages();
    } catch (err) { 
      console.log('CMS not available');
      alert('Erreur: Les tables CMS nexistent peut-être pas. Veuillez runner la migration.'); 
    }
  };

  const handleDeletePage = async (pageId) => {
    if (!window.confirm('Supprimer cette page ?')) return;
    try { 
      await api.delete(`/admin/pages/${pageId}`); 
      setSelectedPage(null); 
      setPageSections([]); 
      loadUserPages(); 
    }
    catch (err) { 
      console.log('CMS not available');
      alert('Erreur: Les tables CMS nexistent peut-être pas.'); 
    }
  };

  const handleCreateSection = (e) => {
    e.preventDefault();
    api.post(`/admin/pages/${selectedPage.id}/sections`, sectionForm)
      .then(() => { 
        setShowSectionModal(false); 
        setSectionForm({ type: 'default', title: '', content: '', position: 0 }); 
        loadPageSections(selectedPage.id); 
      })
      .catch(err => { 
        console.log('CMS not available - tables may not exist');
        alert('Erreur: Les tables CMS nexistent peut-être pas. Veuillez.runner la migration.'); 
      });
  };

  const handleDeleteSection = async (sectionId) => {
    if (!window.confirm('Supprimer cette section ?')) return;
    try { await api.delete(`/admin/sections/${sectionId}`); loadPageSections(selectedPage.id); }
    catch (err) { 
      console.log('CMS not available');
      alert('Erreur: Les tables CMS nexistent peut-être pas.'); 
    }
  };

  const handleCreateCard = (e) => {
    e.preventDefault();
    api.post(`/admin/sections/${editingCardSectionId}/cards`, cardForm)
      .then(() => { 
        setShowCardModal(false); 
        setCardForm({ title: '', description: '', icon: '' }); 
        setEditingCardSectionId(null); 
        loadPageSections(selectedPage.id); 
      })
      .catch(err => { 
        console.log('CMS not available');
        alert('Erreur: Les tables CMS nexistent peut-être pas.'); 
      });
  };

  const handleDeleteCard = async (cardId) => {
    if (!window.confirm('Supprimer cette carte ?')) return;
    try { await api.delete(`/admin/cards/${cardId}`); loadPageSections(selectedPage.id); }
    catch (err) { 
      console.log('CMS not available');
      alert('Erreur: Les tables CMS nexistent peut-être pas.'); 
    }
  };

  const loadContentData = () => {
    setContentData({
      hero: { title: "Devis Gratuit", subtitle: "Assurance Décennale Électricien", buttonText: "Obtenir mon devis" },
      benefits: { title: "Pourquoi nous choisir ?", items: [{ title: "Devis gratuit" }, { title: "Comparatif impartial" }, { title: "Réponse sous 24h" }] },
      features: { title: "Nos garanties", items: [{ title: "RC Pro" }, { title: "Garantie Décennale" }, { title: "Assistance juridique" }] },
      pricing: { title: "Tarifs transparents", plans: [{ name: "Solo" }, { name: "Artisan" }, { name: "Entreprise" }] },
      steps: { title: "Comment ça marche ?", steps: [{ title: "1. Comparez" }, { title: "2. Recevez" }, { title: "3. Économisez" }] },
      faq: { title: "Questions fréquentes", questions: [{ question: "Obligatoire ?" }, { question: "Durée ?" }, { question: "Délai ?" }] },
      cta: { title: "Prêt à economiser ?", buttonText: "Obtenir mon devis gratuit" }
    });
  };

  const handleEditStaticSection = (sectionName, data) => {
    setEditingStaticSection(sectionName);
    setFormData(data);
    setShowEditModal(true);
  };

  const handleSaveStaticSection = (e) => {
    e.preventDefault();
    setContentData({ ...contentData, [editingStaticSection]: formData });
    setShowEditModal(false);
    alert('Contenu mis à jour !');
  };

  const getSectionIcon = (type) => {
    const icons = { hero: 'fa-bolt', features: 'fa-star', benefits: 'fa-handshake', pricing: 'fa-tag', steps: 'fa-list-ol', faq: 'fa-question-circle', cta: 'fa-bullhorn', default: 'fa-th-large' };
    return icons[type] || 'fa-th-large';
  };

  const getSectionTitle = (name) => {
    const titles = { hero: 'Hero', benefits: 'Avantages', features: 'Caractéristiques', pricing: 'Tarifs', steps: 'Étapes', faq: 'FAQ', cta: 'CTA' };
    return titles[name] || name;
  };

  return (
    <AdminLayout>
      <div>
        <div className="mb-6">
          <h1 className="text-3xl font-bold text-gray-900">Gestion du Site Web</h1>
          <p className="text-gray-600 mt-1 text-lg">Gérez le contenu dynamique de votre site</p>
        </div>

        <div className="mb-6 border-b border-gray-200">
          <nav className="-mb-px flex space-x-8">
            <button onClick={() => setActiveTab('content')} className={`py-4 px-1 border-b-2 font-medium text-sm ${activeTab === 'content' ? 'border-yellow-500 text-yellow-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}>
              <i className="fas fa-th-large mr-2"></i>Contenu Dynamique
            </button>
            <button onClick={() => setActiveTab('pages')} className={`py-4 px-1 border-b-2 font-medium text-sm ${activeTab === 'pages' ? 'border-yellow-500 text-yellow-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}>
              <i className="fas fa-file-alt mr-2"></i>Pages CMS
            </button>
          </nav>
        </div>

        {activeTab === 'content' && (
          <div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
              <div className="bg-white rounded-xl shadow-sm border border-gray-100">
                <div className="p-4 border-b border-gray-100 bg-blue-50 flex justify-between items-center">
                  <h2 className="font-bold text-gray-900 flex items-center gap-2"><i className="fas fa-star text-blue-600"></i>Services</h2>
                  <button onClick={() => { setEditingService(null); setServiceForm({ title: '', description: '', icon: '', position: 0 }); setShowServiceModal(true); }} className="bg-yellow-500 text-white px-3 py-1.5 rounded-lg text-sm hover:bg-yellow-600">
                    <i className="fas fa-plus mr-1"></i>Ajouter
                  </button>
                </div>
                <div className="max-h-64 overflow-y-auto divide-y divide-gray-100">
                  {services.length === 0 ? (
                    <div className="p-6 text-center text-gray-500 text-sm">Aucun service</div>
                  ) : (
                    services.map((s) => (
                      <div key={s.id} className="p-3 flex items-center justify-between hover:bg-gray-50">
                        <div className="flex items-center gap-2">
                          <span className="text-lg">{s.icon || '⚡'}</span>
                          <div><div className="font-medium text-sm">{s.title}</div><div className="text-xs text-gray-500 truncate max-w-[200px]">{s.description}</div></div>
                        </div>
                        <div className="flex gap-1">
                          <button onClick={() => { setEditingService(s); setServiceForm({ title: s.title, description: s.description, icon: s.icon, position: s.position || 0 }); setShowServiceModal(true); }} className="text-blue-600 hover:text-blue-800 p-1"><i className="fas fa-edit text-xs"></i></button>
                          <button onClick={() => handleDeleteService(s.id)} className="text-red-600 hover:text-red-800 p-1"><i className="fas fa-trash text-xs"></i></button>
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>

              <div className="bg-white rounded-xl shadow-sm border border-gray-100">
                <div className="p-4 border-b border-gray-100 bg-green-50 flex justify-between items-center">
                  <h2 className="font-bold text-gray-900 flex items-center gap-2"><i className="fas fa-question-circle text-green-600"></i>FAQs</h2>
                  <button onClick={() => { setEditingFaq(null); setFaqForm({ question: '', answer: '', position: 0 }); setShowFaqModal(true); }} className="bg-yellow-500 text-white px-3 py-1.5 rounded-lg text-sm hover:bg-yellow-600">
                    <i className="fas fa-plus mr-1"></i>Ajouter
                  </button>
                </div>
                <div className="max-h-64 overflow-y-auto divide-y divide-gray-100">
                  {faqs.length === 0 ? (
                    <div className="p-6 text-center text-gray-500 text-sm">Aucune FAQ</div>
                  ) : (
                    faqs.map((f) => (
                      <div key={f.id} className="p-3 flex items-center justify-between hover:bg-gray-50">
                        <div className="flex-1 min-w-0"><div className="font-medium text-sm truncate">{f.question}</div></div>
                        <div className="flex gap-1">
                          <button onClick={() => { setEditingFaq(f); setFaqForm({ question: f.question, answer: f.answer, position: f.position || 0 }); setShowFaqModal(true); }} className="text-blue-600 hover:text-blue-800 p-1"><i className="fas fa-edit text-xs"></i></button>
                          <button onClick={() => handleDeleteFaq(f.id)} className="text-red-600 hover:text-red-800 p-1"><i className="fas fa-trash text-xs"></i></button>
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>

              <div className="bg-white rounded-xl shadow-sm border border-gray-100 md:col-span-2">
                <div className="p-4 border-b border-gray-100 bg-purple-50 flex justify-between items-center">
                  <h2 className="font-bold text-gray-900 flex items-center gap-2"><i className="fas fa-tag text-purple-600"></i>Offres</h2>
                  <button onClick={() => { setEditingOffer(null); setOfferForm({ name: '', description: '', price: '', badge: '', features: [], isPopular: false, position: 0 }); setShowOfferModal(true); }} className="bg-yellow-500 text-white px-3 py-1.5 rounded-lg text-sm hover:bg-yellow-600">
                    <i className="fas fa-plus mr-1"></i>Ajouter
                  </button>
                </div>
                <div className="max-h-64 overflow-y-auto divide-y divide-gray-100">
                  {offers.length === 0 ? (
                    <div className="p-6 text-center text-gray-500 text-sm">Aucune offre</div>
                  ) : (
                    offers.map((o) => (
                      <div key={o.id} className="p-3 flex items-center justify-between hover:bg-gray-50">
                        <div className="flex items-center gap-3">
                          <div className="font-medium text-sm">{o.name}</div>
                          <div className="text-sm text-yellow-600 font-bold">{o.price}</div>
                          {o.isPopular && <span className="px-2 py-0.5 bg-yellow-500 text-white text-xs rounded-full">Populaire</span>}
                        </div>
                        <div className="flex gap-1">
                          <button onClick={() => { setEditingOffer(o); setOfferForm({ name: o.name, description: o.description, price: o.price, badge: o.badge, features: o.features || [], isPopular: o.isPopular, position: o.position || 0 }); setShowOfferModal(true); }} className="text-blue-600 hover:text-blue-800 p-1"><i className="fas fa-edit text-xs"></i></button>
                          <button onClick={() => handleDeleteOffer(o.id)} className="text-red-600 hover:text-red-800 p-1"><i className="fas fa-trash text-xs"></i></button>
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'pages' && (
<div>
<div className="mb-6 flex items-center justify-between">
              <p className="text-gray-600">Creez des pages completes avec sections et cartes</p>
              <button onClick={() => setShowNewPageModal(true)} className="bg-yellow-500 text-white px-5 py-2.5 rounded-lg hover:bg-yellow-600 font-medium flex items-center gap-2 shadow-md">
                <i className="fas fa-plus"></i> Nouvelle Page
              </button>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              {/* Left: Pages */}
              <div className="bg-white rounded-xl shadow-sm border border-gray-100">
                <div className="p-5 border-b border-gray-100 bg-purple-50">
                  <h2 className="text-xl font-bold text-gray-900 flex items-center gap-2"><i className="fas fa-file-alt text-purple-600"></i> Pages</h2>
                </div>
                <div className="divide-y divide-gray-100 max-h-[500px] overflow-y-auto">
                  {userPages.length === 0 ? (
                    <div className="p-8 text-center text-gray-500"><i className="fas fa-folder-open text-4xl text-gray-300 mb-3"></i><p>Aucune page</p></div>
                  ) : (
                    userPages.map((page) => (
                      <div key={page.id} className={`p-4 flex items-center justify-between hover:bg-gray-50 cursor-pointer ${selectedPage?.id === page.id ? 'bg-yellow-50 border-l-4 border-yellow-500' : ''}`} onClick={() => handleSelectPage(page)}>
                        <div><h3 className="font-medium text-gray-900">{page.title}</h3><p className="text-sm text-gray-500">/{page.slug}</p></div>
                        <div className="flex items-center gap-2">
                          <span className={`px-2 py-1 text-xs rounded-full ${page.isPublished ? 'bg-green-100 text-green-600' : 'bg-gray-100 text-gray-600'}`}>{page.isPublished ? 'Publié' : 'Brouillon'}</span>
                          <button onClick={(e) => { e.stopPropagation(); handleDeletePage(page.id); }} className="text-red-600 hover:text-red-800 p-2"><i className="fas fa-trash"></i></button>
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>

              {/* Right: Sections */}
              <div className="bg-white rounded-xl shadow-sm border border-gray-100">
                <div className="p-5 border-b border-gray-100 bg-yellow-50 flex items-center justify-between">
                  <div>
                    <h2 className="text-xl font-bold text-gray-900 flex items-center gap-2"><i className="fas fa-layer-group text-yellow-600"></i> Sections & Cartes</h2>
                    {selectedPage && <p className="text-sm text-gray-500 mt-1">Page: {selectedPage.title}</p>}
                  </div>
                  {selectedPage && <button onClick={() => setShowSectionModal(true)} className="bg-yellow-500 text-white px-3 py-2 rounded-lg hover:bg-yellow-600 text-sm"><i className="fas fa-plus mr-1"></i> Section</button>}
                </div>
                <div className="divide-y divide-gray-100 max-h-[500px] overflow-y-auto">
                  {!selectedPage ? (
                    <div className="p-8 text-center text-gray-500"><i className="fas fa-hand-pointer text-4xl text-gray-300 mb-3"></i><p>Sélectionnez une page</p></div>
                  ) : pageSections.length === 0 ? (
                    <div className="p-8 text-center text-gray-500"><i className="fas fa-th-large text-4xl text-gray-300 mb-3"></i><p>Aucune section</p></div>
                  ) : (
                    pageSections.map((section) => (
                      <div key={section.id} className="p-4">
                        <div className="flex items-center justify-between mb-2">
                          <div className="flex items-center gap-3">
                            <div className="w-10 h-10 bg-yellow-100 rounded-lg flex items-center justify-center"><i className={`fas ${getSectionIcon(section.type)} text-yellow-600`}></i></div>
                            <div><h4 className="font-medium text-gray-900">{section.title || 'Section'}</h4><p className="text-xs text-gray-500">{section.type}</p></div>
                          </div>
                          <button onClick={() => handleDeleteSection(section.id)} className="text-red-600 hover:text-red-800"><i className="fas fa-trash"></i></button>
                        </div>
                        <div className="ml-13 pl-13">
                          <div className="flex items-center justify-between mb-2"><span className="text-sm font-medium text-gray-700">Cartes</span><button onClick={() => { setEditingCardSectionId(section.id); setShowCardModal(true); }} className="text-xs text-yellow-600">+ Ajouter</button></div>
                          {section.cards?.length > 0 ? (
                            <div className="space-y-1">{section.cards.map((card) => (<div key={card.id} className="bg-gray-50 rounded p-2 flex items-center justify-between"><div className="flex items-center gap-2">{card.icon && <i className={`fas ${card.icon} text-yellow-500`}></i>}<span className="text-sm">{card.title}</span></div><button onClick={() => handleDeleteCard(card.id)} className="text-red-500 text-xs">×</button></div>))}</div>
                          ) : (<p className="text-xs text-gray-400">Aucune carte</p>)}
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>
            </div>
          </div>
)}

        {/* New Page Modal */}

        {/* New Page Modal */}
        {showNewPageModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl w-full max-w-md">
              <div className="p-5 border-b border-gray-100 flex justify-between items-center"><h2 className="text-xl font-bold">Nouvelle Page</h2><button onClick={() => setShowNewPageModal(false)} className="text-2xl text-gray-400">×</button></div>
              <form onSubmit={handleCreatePage} className="p-5 space-y-4">
                <div><label className="block text-sm font-medium mb-1">Titre</label><input type="text" value={newPageForm.title} onChange={(e) => setNewPageForm({ ...newPageForm, title: e.target.value, slug: e.target.value.toLowerCase().replace(/\s+/g, '-') })} className="w-full px-4 py-2 border rounded-lg" required /></div>
                <div><label className="block text-sm font-medium mb-1">URL</label><input type="text" value={newPageForm.slug} onChange={(e) => setNewPageForm({ ...newPageForm, slug: e.target.value.toLowerCase().replace(/\s+/g, '-') })} className="w-full px-4 py-2 border rounded-lg" required /></div>
                <div className="flex items-center gap-2"><input type="checkbox" checked={newPageForm.isPublished} onChange={(e) => setNewPageForm({ ...newPageForm, isPublished: e.target.checked })} /><span className="text-sm">Publier</span></div>
                <div className="flex gap-2 pt-4"><button type="button" onClick={() => setShowNewPageModal(false)} className="flex-1 py-2 border rounded-lg">Annuler</button><button type="submit" className="flex-1 py-2 bg-yellow-500 text-white rounded-lg">Créer</button></div>
              </form>
            </div>
          </div>
        )}

        {/* New Section Modal */}
        {showSectionModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl w-full max-w-md">
              <div className="p-5 border-b border-gray-100 flex justify-between items-center"><h2 className="text-xl font-bold">Nouvelle Section</h2><button onClick={() => setShowSectionModal(false)} className="text-2xl text-gray-400">×</button></div>
              <form onSubmit={handleCreateSection} className="p-5 space-y-4">
                <div><label className="block text-sm font-medium mb-1">Type</label><select value={sectionForm.type} onChange={(e) => setSectionForm({ ...sectionForm, type: e.target.value })} className="w-full px-4 py-2 border rounded-lg"><option value="default">Default</option><option value="hero">Hero</option><option value="features">Features</option><option value="benefits">Benefits</option><option value="pricing">Pricing</option><option value="steps">Steps</option><option value="faq">FAQ</option><option value="cta">CTA</option></select></div>
                <div><label className="block text-sm font-medium mb-1">Titre</label><input type="text" value={sectionForm.title} onChange={(e) => setSectionForm({ ...sectionForm, title: e.target.value })} className="w-full px-4 py-2 border rounded-lg" /></div>
                <div><label className="block text-sm font-medium mb-1">Contenu</label><textarea value={sectionForm.content} onChange={(e) => setSectionForm({ ...sectionForm, content: e.target.value })} className="w-full px-4 py-2 border rounded-lg" rows={3} /></div>
                <div className="flex gap-2 pt-4"><button type="button" onClick={() => setShowSectionModal(false)} className="flex-1 py-2 border rounded-lg">Annuler</button><button type="submit" className="flex-1 py-2 bg-yellow-500 text-white rounded-lg">Créer</button></div>
              </form>
            </div>
          </div>
        )}

        {/* New Card Modal */}
        {showCardModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl w-full max-w-md">
              <div className="p-5 border-b border-gray-100 flex justify-between items-center"><h2 className="text-xl font-bold">Nouvelle Carte</h2><button onClick={() => setShowCardModal(false)} className="text-2xl text-gray-400">×</button></div>
              <form onSubmit={handleCreateCard} className="p-5 space-y-4">
                <div><label className="block text-sm font-medium mb-1">Titre</label><input type="text" value={cardForm.title} onChange={(e) => setCardForm({ ...cardForm, title: e.target.value })} className="w-full px-4 py-2 border rounded-lg" /></div>
                <div><label className="block text-sm font-medium mb-1">Description</label><textarea value={cardForm.description} onChange={(e) => setCardForm({ ...cardForm, description: e.target.value })} className="w-full px-4 py-2 border rounded-lg" rows={2} /></div>
                <div><label className="block text-sm font-medium mb-1">Icône (fa-star)</label><input type="text" value={cardForm.icon} onChange={(e) => setCardForm({ ...cardForm, icon: e.target.value })} className="w-full px-4 py-2 border rounded-lg" placeholder="fa-check" /></div>
                <div className="flex gap-2 pt-4"><button type="button" onClick={() => setShowCardModal(false)} className="flex-1 py-2 border rounded-lg">Annuler</button><button type="submit" className="flex-1 py-2 bg-yellow-500 text-white rounded-lg">Créer</button></div>
              </form>
            </div>
          </div>
        )}

        {/* Edit Static Content Modal */}
        {showEditModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl w-full max-w-lg max-h-[80vh] overflow-y-auto">
              <div className="p-5 border-b border-gray-100 flex justify-between items-center"><h2 className="text-xl font-bold">{getSectionTitle(editingStaticSection)}</h2><button onClick={() => setShowEditModal(false)} className="text-2xl text-gray-400">×</button></div>
              <form onSubmit={handleSaveStaticSection} className="p-5 space-y-4">
                <div><label className="block text-sm font-medium mb-1">Titre</label><input type="text" value={formData.title || ''} onChange={(e) => setFormData({ ...formData, title: e.target.value })} className="w-full px-4 py-2 border rounded-lg" /></div>
                <div className="flex gap-2 pt-4"><button type="button" onClick={() => setShowEditModal(false)} className="flex-1 py-2 border rounded-lg">Annuler</button><button type="submit" className="flex-1 py-2 bg-yellow-500 text-white rounded-lg">Sauvegarder</button></div>
              </form>
            </div>
          </div>
        )}

        {/* Service Modal */}
        {showServiceModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl w-full max-w-md">
              <div className="p-5 border-b border-gray-100 flex justify-between items-center"><h2 className="text-xl font-bold">{editingService ? 'Modifier' : 'Nouveau'} Service</h2><button onClick={() => { setShowServiceModal(false); setEditingService(null); }} className="text-2xl text-gray-400">×</button></div>
              <form onSubmit={handleCreateService} className="p-5 space-y-4">
                <div><label className="block text-sm font-medium mb-1">Titre</label><input type="text" value={serviceForm.title} onChange={(e) => setServiceForm({ ...serviceForm, title: e.target.value })} className="w-full px-4 py-2 border rounded-lg" required /></div>
                <div><label className="block text-sm font-medium mb-1">Description</label><textarea value={serviceForm.description} onChange={(e) => setServiceForm({ ...serviceForm, description: e.target.value })} className="w-full px-4 py-2 border rounded-lg" rows={3} /></div>
                <div><label className="block text-sm font-medium mb-1">Icone (emoji)</label><input type="text" value={serviceForm.icon} onChange={(e) => setServiceForm({ ...serviceForm, icon: e.target.value })} className="w-full px-4 py-2 border rounded-lg" placeholder="⚡" /></div>
                <div><label className="block text-sm font-medium mb-1">Position</label><input type="number" value={serviceForm.position} onChange={(e) => setServiceForm({ ...serviceForm, position: parseInt(e.target.value) })} className="w-full px-4 py-2 border rounded-lg" /></div>
                <div className="flex gap-2 pt-4"><button type="button" onClick={() => { setShowServiceModal(false); setEditingService(null); }} className="flex-1 py-2 border rounded-lg">Annuler</button><button type="submit" className="flex-1 py-2 bg-yellow-500 text-white rounded-lg">{editingService ? 'Mettre a jour' : 'Creer'}</button></div>
              </form>
            </div>
          </div>
        )}

        {/* FAQ Modal */}
        {showFaqModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl w-full max-w-md">
              <div className="p-5 border-b border-gray-100 flex justify-between items-center"><h2 className="text-xl font-bold">{editingFaq ? 'Modifier' : 'Nouvelle'} FAQ</h2><button onClick={() => { setShowFaqModal(false); setEditingFaq(null); }} className="text-2xl text-gray-400">×</button></div>
              <form onSubmit={handleCreateFaq} className="p-5 space-y-4">
                <div><label className="block text-sm font-medium mb-1">Question</label><input type="text" value={faqForm.question} onChange={(e) => setFaqForm({ ...faqForm, question: e.target.value })} className="w-full px-4 py-2 border rounded-lg" required /></div>
                <div><label className="block text-sm font-medium mb-1">Reponse</label><textarea value={faqForm.answer} onChange={(e) => setFaqForm({ ...faqForm, answer: e.target.value })} className="w-full px-4 py-2 border rounded-lg" rows={3} /></div>
                <div><label className="block text-sm font-medium mb-1">Position</label><input type="number" value={faqForm.position} onChange={(e) => setFaqForm({ ...faqForm, position: parseInt(e.target.value) })} className="w-full px-4 py-2 border rounded-lg" /></div>
                <div className="flex gap-2 pt-4"><button type="button" onClick={() => { setShowFaqModal(false); setEditingFaq(null); }} className="flex-1 py-2 border rounded-lg">Annuler</button><button type="submit" className="flex-1 py-2 bg-yellow-500 text-white rounded-lg">{editingFaq ? 'Mettre a jour' : 'Creer'}</button></div>
              </form>
            </div>
          </div>
        )}

        {/* Offer Modal */}
        {showOfferModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl w-full max-w-md">
              <div className="p-5 border-b border-gray-100 flex justify-between items-center"><h2 className="text-xl font-bold">{editingOffer ? 'Modifier' : 'Nouvelle'} Offre</h2><button onClick={() => { setShowOfferModal(false); setEditingOffer(null); }} className="text-2xl text-gray-400">×</button></div>
              <form onSubmit={handleCreateOffer} className="p-5 space-y-4">
                <div><label className="block text-sm font-medium mb-1">Nom</label><input type="text" value={offerForm.name} onChange={(e) => setOfferForm({ ...offerForm, name: e.target.value })} className="w-full px-4 py-2 border rounded-lg" required /></div>
                <div><label className="block text-sm font-medium mb-1">Description</label><textarea value={offerForm.description} onChange={(e) => setOfferForm({ ...offerForm, description: e.target.value })} className="w-full px-4 py-2 border rounded-lg" rows={2} /></div>
                <div><label className="block text-sm font-medium mb-1">Prix</label><input type="text" value={offerForm.price} onChange={(e) => setOfferForm({ ...offerForm, price: e.target.value })} className="w-full px-4 py-2 border rounded-lg" placeholder="600-900€/an" /></div>
                <div><label className="block text-sm font-medium mb-1">Badge</label><input type="text" value={offerForm.badge} onChange={(e) => setOfferForm({ ...offerForm, badge: e.target.value })} className="w-full px-4 py-2 border rounded-lg" placeholder="Le plus populaire" /></div>
                <div className="flex items-center gap-2"><input type="checkbox" checked={offerForm.isPopular} onChange={(e) => setOfferForm({ ...offerForm, isPopular: e.target.checked })} /><span className="text-sm">Populaire</span></div>
                <div><label className="block text-sm font-medium mb-1">Position</label><input type="number" value={offerForm.position} onChange={(e) => setOfferForm({ ...offerForm, position: parseInt(e.target.value) })} className="w-full px-4 py-2 border rounded-lg" /></div>
                <div className="flex gap-2 pt-4"><button type="button" onClick={() => { setShowOfferModal(false); setEditingOffer(null); }} className="flex-1 py-2 border rounded-lg">Annuler</button><button type="submit" className="flex-1 py-2 bg-yellow-500 text-white rounded-lg">{editingOffer ? 'Mettre a jour' : 'Creer'}</button></div>
              </form>
            </div>
          </div>
        )}
      </div>
    </AdminLayout>
  );
}
